            case "1.00":
                return "mdpi / 1x / " + getDpi(scaleString);
            case "1.50":
                return "hdpi / " + getDpi(scaleString);
            case "2.00":
                return "xhdpi / 2x / " + getDpi(scaleString);
            case "3.00":
                return "xxhdpi / 3x / " + getDpi(scaleString);
            case "4.00":
                return "xxxhdpi / " + getDpi(scaleString);
            default:
                return getDpi(scaleString);
        }
    }

